interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  name: string;
  type?: string;
}

export default function Input({ name, type = "text", ...props }: InputProps) {
  return (
    <>
      <input
        className="text-white font-semibold placeholder:text-white bg-transparent border border-purple rounded px-8 py-2 w-full focus:border-soft-purple outline-0 focus:shadow-purple focus:shadow-custom transition-all duration-200"
        id={name}
        name={name}
        type={type}
        {...props}
        required
      />
    </>
  );
}
