import Link from 'next/link'
import Form from '../components/Form'
import Input from '../components/Input'
import Label from '../components/Label'
import InputPassword from '../components/InputPassword'
import { Button } from '@/components/ui/button'

export default function LoginPage() {
    return (
        <section className="h-screen flex flex-col justify-center items-center text-white">
            <h1 className="font-black text-4xl mb-5">Login administrador</h1>
            <Form>
                <Label htmlFor="email">Email:</Label>
                <Input
                    name="email"
                    type="email"
                    autoComplete="email"
                    placeholder="Email"
                    autoFocus={true}
                />
                <Label htmlFor="password">Senha:</Label>
                <InputPassword />
                <Button
                    type="submit"
                    variant={'outline'}
                    className="bg-transparent font-semibold px-4 py-2 rounded mt-4 cursor-pointer"
                >
                    Entrar
                </Button>
            </Form>
        </section>
    )
}
